using System;
using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver.
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ──────────────────────────────────────────────────────
// 1. Strongly-typed metadata: GetTypeInfo<T>()
//    Returns JsonTypeInfo<T> directly — no casting needed.
// ──────────────────────────────────────────────────────
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type info for Person : {personInfo.Type.Name}  (kind: {personInfo.Kind})");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized           : {json}");

Person roundTripped = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Round-tripped        : {roundTripped}");

// ──────────────────────────────────────────────────────
// 2. Probe-without-throwing: TryGetTypeInfo<T>()
//    Returns false instead of throwing when metadata
//    is not available.
// ──────────────────────────────────────────────────────

// 2a. A type the resolver knows about → should succeed.
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"\nTryGetTypeInfo<Person> succeeded — kind: {found.Kind}");
else
    Console.WriteLine("\nTryGetTypeInfo<Person> returned false (unexpected)");

// 2b. Use an options instance whose resolver only handles
//     a specific set of types, so probing an unregistered
//     type returns false rather than throwing.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new LimitedResolver()   // resolves nothing
};

if (limited.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? notFound))
    Console.WriteLine($"TryGetTypeInfo<Person> on limited resolver succeeded (unexpected)");
else
    Console.WriteLine($"TryGetTypeInfo<Person> on limited resolver returned false — no exception!");

// ── helpers ──────────────────────────────────────────
record Person(string Name, int Age);

/// A resolver that deliberately provides no metadata for any type.
sealed class LimitedResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

